const queries = [
  // === CRUNCHBASE — recently funded companies ===
  { q: 'site:crunchbase.com/organization "seed" "AI" OR "machine learning" OR "automation" OR "SaaS" 2025', platform: 'crunchbase', signal: 'funding' },
  { q: 'site:crunchbase.com/organization "series a" "AI" OR "machine learning" OR "automation" OR "software" 2025', platform: 'crunchbase', signal: 'funding' },
  { q: 'site:crunchbase.com/organization "series b" "AI" OR "automation" OR "enterprise software" 2024 OR 2025', platform: 'crunchbase', signal: 'funding' },

  // === TECHCRUNCH funding announcements ===
  { q: 'site:techcrunch.com "raises" "$" "million" "AI" OR "machine learning" OR "automation" OR "SaaS" 2025', platform: 'techcrunch', signal: 'funding' },
  { q: 'site:techcrunch.com "seed round" OR "series a" OR "series b" "AI startup" OR "SaaS startup" OR "automation" 2025', platform: 'techcrunch', signal: 'funding' },
  { q: 'site:techcrunch.com "funding" "AI" OR "machine learning" "hiring" OR "expand" OR "build" 2025', platform: 'techcrunch', signal: 'funding' },

  // === VENTUREBEAT ===
  { q: 'site:venturebeat.com "raises" OR "raised" "million" "AI" OR "automation" OR "machine learning" 2025', platform: 'venturebeat', signal: 'funding' },
  { q: 'site:venturebeat.com "seed" OR "series a" "AI startup" OR "automation" OR "SaaS" "funding" 2024 OR 2025', platform: 'venturebeat', signal: 'funding' },

  // === LINKEDIN — job posting surge (hiring without filling = outsourcing signal) ===
  { q: 'site:linkedin.com/jobs "software engineer" OR "ML engineer" OR "AI engineer" "seed funded" OR "recently funded" OR "series a"', platform: 'linkedin_jobs', signal: 'hiring_surge' },
  { q: 'site:linkedin.com/jobs "backend engineer" OR "full stack engineer" OR "data engineer" "AI startup" OR "funded startup" OR "early stage"', platform: 'linkedin_jobs', signal: 'hiring_surge' },
  { q: 'site:linkedin.com/jobs "CTO" OR "VP engineering" OR "head of engineering" "AI" OR "automation" "startup" OR "seed" OR "series a"', platform: 'linkedin_jobs', signal: 'hiring_surge' },

  // === LINKEDIN posts — funding announcements ===
  { q: 'site:linkedin.com/posts "just raised" OR "we raised" "building" OR "hiring" "AI" OR "software" OR "automation" 2025', platform: 'linkedin_posts', signal: 'funding' },
  { q: 'site:linkedin.com/posts "excited to announce" "funding" OR "investment" "AI" OR "machine learning" OR "automation" 2025', platform: 'linkedin_posts', signal: 'funding' },

  // === INDEED — engineering hiring signals ===
  { q: 'site:indeed.com "software engineer" OR "ML engineer" OR "AI engineer" "startup" OR "series a funded" OR "seed stage"', platform: 'indeed', signal: 'hiring_surge' },

  // === GLASSDOOR ===
  { q: 'site:glassdoor.com "software engineer" OR "machine learning engineer" "startup" OR "seed" OR "series a" "AI" OR "automation"', platform: 'glassdoor', signal: 'hiring_surge' },

  // === GENERAL FUNDING NEWS ===
  { q: '"raises" "$" "million" "AI" OR "machine learning" OR "automation" "seed" OR "series a" site:businessinsider.com OR site:forbes.com 2025', platform: 'news', signal: 'funding' },
  { q: 'site:eu.startups.com OR site:sifted.eu "raises" "million" "AI" OR "automation" OR "software" 2025', platform: 'news', signal: 'funding' },
];
return queries.map(q => ({ json: q }));

const skipKeywords = [
  'apply now', 'job description', 'salary range', 'benefits package',
  'equal opportunity', 'we are an equal', 'submit your resume',
  'years of experience required', 'bachelor degree required'
];

const platformMap = {
  'crunchbase.com': 'crunchbase',
  'techcrunch.com': 'techcrunch',
  'venturebeat.com': 'venturebeat',
  'linkedin.com/jobs': 'linkedin_jobs',
  'linkedin.com/posts': 'linkedin_posts',
  'linkedin.com/in': 'linkedin_posts',
  'indeed.com': 'indeed',
  'glassdoor.com': 'glassdoor',
  'businessinsider.com': 'news',
  'forbes.com': 'news',
  'eu.startups.com': 'news',
  'sifted.eu': 'news'
};

const budgetPatterns = [
  /\$(\d+(?:\.\d+)?)\s*(?:million|M)\b/i,
  /raised\s+([\$\€][\d,.]+\s*(?:million|M|billion|B)?)/i,
  /([\$\€][\d,.]+\s*(?:million|M|billion|B)\s*(?:seed|series [ab]|funding|round)?)/i,
];

const results = [];
const seenInRun = new Set();

for (const item of $input.all()) {
  const data = item.json;
  if (!data || data.error) continue;

  const searchQ = data.search_parameters?.q || '';
  const organicResults = data.organic_results || [];

  // Detect signal type from query
  const signal = searchQ.includes('engineer') || searchQ.includes('hiring') || searchQ.includes('glassdoor') || searchQ.includes('indeed') ? 'hiring_surge' : 'funding';

  for (const r of organicResults) {
    const link = r.link || '';
    if (!link) continue;

    // Detect platform from URL
    let platform = 'unknown';
    for (const [domain, pname] of Object.entries(platformMap)) {
      if (link.includes(domain)) { platform = pname; break; }
    }
    if (platform === 'unknown') {
      // Try generic news
      if (link.includes('techcrunch') || link.includes('venturebeat') || link.includes('forbes') || link.includes('businessinsider') || link.includes('sifted') || link.includes('eu.startups')) {
        platform = 'news';
      }
    }
    if (platform === 'unknown') continue;

    const id = platform + '_' + link.replace(/[^a-z0-9]/gi, '').slice(-70);
    if (seenInRun.has(id)) continue;
    seenInRun.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (skipKeywords.some(kw => fullText.includes(kw))) continue;

    // Extract funding amount from snippet/title
    let budget_text = '';
    for (const pat of budgetPatterns) {
      const m = (snippet + ' ' + title).match(pat);
      if (m) { budget_text = (m[1] || m[0]).trim().substring(0, 80); break; }
    }

    // Detect funding stage
    let flair = signal === 'hiring_surge' ? 'Hiring Surge' : 'Funding';
    const combined = (title + ' ' + snippet).toLowerCase();
    if (combined.includes('series b')) flair = 'Series B';
    else if (combined.includes('series a')) flair = 'Series A';
    else if (combined.includes('seed')) flair = 'Seed';
    else if (combined.includes('pre-seed') || combined.includes('pre seed')) flair = 'Pre-Seed';
    else if (signal === 'hiring_surge') flair = 'Hiring Surge';

    results.push({ json: {
      title,
      description: snippet,
      source: platform,
      source_url: link,
      source_id: id,
      posted_at: (() => { try { const d = r.date ? new Date(r.date) : null; return (d && !isNaN(d)) ? d.toISOString() : new Date().toISOString(); } catch(e) { return new Date().toISOString(); } })(),
      author: '',
      subreddit: flair,
      upvotes: 0,
      num_comments: 0,
      flair_text: flair,
      budget_text,
      signal,
      platform
    }});
  }
}

if (results.length === 0) return [{ json: { _empty: true, platform: 'venture' } }];
// Cap at 30 leads per run to avoid Gemini rate-limit timeouts
return results.slice(0, 30);

const post = $input.item.json;
if (post._empty || post._noData) return { json: post };

const apiKey = $env.GOOGLE_AI_API_KEY;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, custom software, data pipelines.

These leads are venture funding signals and engineering hiring surge signals. The core logic:
- Company raised $2M-$50M → needs to build fast → high probability outsourcing candidate
- Company posting 3+ engineering roles but small team → can't hire fast enough → outsourcing opportunity
- Recently funded AI/SaaS startup → needs custom ML/AI/automation built → perfect ScaleBuild fit


HARD EXCLUSIONS — Score overall_score 0.0 immediately, do not process:
- Lead is from India or an Indian company (location: India, .in domain, Indian city/company name context) → 0.0
- Lead is requesting to build a SaaS subscription product (we do NOT build SaaS products) → 0.0  
- Budget is clearly under $10,000 OR budget_score would be below 0.3 → 0.0
- Individual freelancer or [For Hire] ad → 0.0

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 1.0=AI/ML/automation startup just funded | 0.8=SaaS/software startup with dev needs | 0.6=tech-adjacent startup | 0.3=non-tech | 0.0=no fit
2. budget_score (based on funding amount):
   - $50M+ raised → 1.0 | $20-50M → 0.9 | $10-20M → 0.8 | $5-10M → 0.7 | $2-5M → 0.6 | $500K-2M → 0.5 | unknown/hiring signal → 0.5
3. urgency_score: 1.0=announced this week/month | 0.8=within 3 months of funding | 0.6=6 months post-funding | 0.5=hiring surge now | 0.3=older signal | 0.1=no urgency
4. win_probability: 0.9=small team + funded + AI focus | 0.8=funded + engineering hiring | 0.7=funded + tech needs | 0.5=medium fit | 0.3=large company/already staffed | 0.1=no fit

KEY SIGNALS TO LOOK FOR:
- Team size <10 engineers + $2M+ raised = VERY HIGH priority
- 3+ engineering job postings open = outsourcing signal
- "building AI" / "automating" / "data pipeline" mentioned = perfect fit
- Founder/CTO posting about hiring difficulty = outsourcing signal

BUDGET ESTIMATION (ALWAYS fill estimated_budget_text, never null. Base on funding raised):
- Raised $20M-$50M → "$50K-$300K (post-Series A build budget)"
- Raised $5M-$20M → "$25K-$150K (seed/Series A scope)"
- Raised $1M-$5M → "$15K-$75K (seed stage scope)"
- Hiring surge (no funding data) → "$20K-$100K (engineering outsource)"
- Unknown → "$15K-$80K (estimated startup scope)"

COMPANY EXTRACTION: Extract company name, founder name, website from snippet/URL. Never invent.`;

const prompt = SYSTEM_PROMPT + `

Score this venture/hiring signal lead. Return ONLY a single valid JSON object:
{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"summary":"3-5 sentence detailed summary: what the company does, funding amount/stage, team size signals, why ScaleBuild AI is the right fit","industry":"FinTech/HealthTech/SaaS/AI/Manufacturing/eCommerce/General","tags":["tag1","tag2"],"reasoning":"Full detailed reasoning: explain each score dimension — why this relevance, why this budget score (funding amount), why this urgency, why this win probability. What specific signals make this a strong or weak lead. Recommended outreach angle.","estimated_budget_text":"$X-$Y (reason)","funding_stage":"Seed/Series A/Series B/Unknown","funding_amount":"$XM or unknown","tech_stack":[],"company_name":null,"lead_founder_name":null,"lead_website":null}

Title: ${post.title}
Platform: ${post.source}
Signal Type: ${post.signal || 'funding'}
Funding Stage: ${post.flair_text || 'Unknown'}
Description: ${(post.description||'').substring(0, 1200)}${post.budget_text ? '\nFunding Amount Mentioned: ' + post.budget_text : ''}`;

const body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { maxOutputTokens: 100000, temperature: 0.2, responseMimeType: 'application/json' }
};

let s = null;
try {
  const respRaw = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
    body
  });
  const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
  const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) s = JSON.parse(match[0]);
} catch(e) {}

if (!s) s = {
  relevance_score:0.4, budget_score:0.5, urgency_score:0.4, win_probability:0.4,
  summary:'Parse error', industry:'General', tags:[], reasoning:'Could not parse Gemini response',
  estimated_budget_text:'$15K-$75K (estimated)', funding_stage:'Unknown',
  funding_amount:'unknown', tech_stack:[],
  company_name:null, lead_founder_name:null, lead_website:null
};

const overall = Math.round(((s.relevance_score*0.35)+(s.budget_score*0.30)+(s.urgency_score*0.15)+(s.win_probability*0.20))*100)/100;
const alert_tier = overall>=0.85?'instant':overall>=0.70?'digest':overall>=0.30?'dashboard':'discard';

return { json: {
  source_id: post.source_id, title: post.title, description: post.description,
  source: post.source, source_url: post.source_url, posted_at: post.posted_at,
  author: post.author||'', subreddit: post.flair_text||post.signal||'funding',
  upvotes: 0, num_comments: 0, flair_text: post.flair_text||'Funding',
  relevance_score: s.relevance_score, budget_score: s.budget_score,
  urgency_score: s.urgency_score, win_probability: s.win_probability,
  overall_score: overall, ai_summary: s.summary, industry: s.industry,
  ai_tags: s.tags||[], ai_reasoning: s.reasoning,
  estimated_budget_text: s.estimated_budget_text||'',
  budget_mentioned: post.budget_text || s.funding_amount || s.estimated_budget_text || '',
  tech_stack: s.tech_stack||[], company_name: s.company_name||null,
  lead_founder: s.lead_founder_name||null, lead_company: s.company_name||null,
  lead_website: s.lead_website||null, lead_contact: null,
  lead_score: Math.round(overall*10),
  alert_tier, discovered_at: new Date().toISOString(), status:'new',
  location: s.location||null, deadline_text: null,
  outreach_draft: '',
  hunter_name:'', hunter_email:'', hunter_title:'', hunter_company:''
}};

const hunterResp = $input.item.json;
const original = $('Check - Has Lead Info').item.json;
const data = hunterResp?.data || {};
const emails = data.emails || [];
const org = data.organization || original.lead_company || '';

if (emails.length === 0) {
  return [{ json: { ...original, hunter_name: '', hunter_email: '', hunter_title: '', hunter_company: org, hunter_all_emails: '', hunter_all_names: '', hunter_all_titles: '' } }];
}

// Pick best contact by seniority priority
const priority = ['ceo','founder','co-founder','cto','owner','president','vp','director'];
const best = emails.find(e => priority.some(t => (e.position||'').toLowerCase().includes(t))) || emails[0];

// Collect all emails, names, titles as comma-separated
const allEmails  = emails.map(e => e.value || '').filter(Boolean).join(', ');
const allNames   = emails.map(e => (e.first_name||e.last_name) ? `${e.first_name||''} ${e.last_name||''}`.trim() : '').filter(Boolean).join(', ');
const allTitles  = emails.map(e => e.position || '').filter(Boolean).join(', ');

return [{ json: {
  ...original,
  hunter_name:       best.first_name || best.last_name ? `${best.first_name||''} ${best.last_name||''}`.trim() : '',
  hunter_email:      best.value || '',
  hunter_title:      best.position || '',
  hunter_company:    org,
  hunter_all_emails: allEmails,
  hunter_all_names:  allNames,
  hunter_all_titles: allTitles
}}];

const seen = new Map();
for (const item of $input.all()) {
  const id = item.json.source_id;
  if (!id) continue;
  if (!seen.has(id)) {
    seen.set(id, item.json);
  } else {
    if (item.json.hunter_email && !seen.get(id).hunter_email) {
      seen.set(id, item.json);
    }
  }
}
return [...seen.values()]
  .sort((a, b) => (b.overall_score||0) - (a.overall_score||0))
  .map(json => ({ json }));
